import {
  Box,
  Card,
  Center,
  Combobox,
  Input,
  InputBase,
  Loader,
  Stack,
  Text,
  Title,
  UnstyledButton,
  useCombobox,
} from '@mantine/core';
import { UrlResponse } from '@/src/entities';
import classes from './UrlList.module.css';

interface UrlListProps {
  urls: UrlResponse[];
  isLoading: boolean;
  errorMsg?: string;
  selectedUrlId: number | null;
  onSelect: (id: number) => void;
}

export function UrlList({ urls, isLoading, errorMsg, selectedUrlId, onSelect }: UrlListProps) {
  const combobox = useCombobox({
    onDropdownClose: () => combobox.resetSelectedOption(),
  });

  const selectedUrl = urls.find((url) => url.id === selectedUrlId);

  if (isLoading) {
    return (
      <Card withBorder radius="md" padding="lg">
        <Title order={3} mb="md">
          Your links
        </Title>
        <Center className={classes.loading}>
          <Loader color="yellow.5" />
        </Center>
      </Card>
    );
  }

  if (errorMsg) {
    return (
      <Card withBorder radius="md" padding="lg">
        <Title order={3} mb="md">
          Your links
        </Title>
        <Text c="red" size="sm">
          { errorMsg }
        </Text>
      </Card>
    );
  }

  if (urls.length === 0) {
    return (
      <Card withBorder radius="md" padding="lg">
        <Title order={3} mb="md">
          Your links
        </Title>
        <Text c="dimmed" size="sm">
          You haven&apos;t shortened any links yet.
        </Text>
      </Card>
    );
  }

  return (
    <Card withBorder radius="md" padding="lg">
      <Title order={3} mb="md">
        Your links
      </Title>

      <Box visibleFrom="lg">
        <Stack gap={4}>
          {urls.map((url) => (
            <UnstyledButton
              key={url.id}
              className={classes.item}
              data-active={url.id === selectedUrlId || undefined}
              onClick={() => onSelect(url.id)}
            >
              <Text className={classes.shortUrl} fw={600} size="sm">
                {url.mapped_url_id}
              </Text>
              <Text c="dimmed" size="xs" truncate>
                {url.original_url}
              </Text>
            </UnstyledButton>
          ))}
        </Stack>
      </Box>

      <Box hiddenFrom="lg">
        <Combobox
          store={combobox}
          onOptionSubmit={(value) => {
            onSelect(Number(value));
            combobox.closeDropdown();
          }}
        >
          <Combobox.Target>
            <InputBase
              className={classes.combobox}
              component="button"
              type="button"
              pointer
              rightSection={<Combobox.Chevron />}
              onClick={() => combobox.toggleDropdown()}
            >
              {selectedUrl ? (
                <>
                  <Text className={classes.shortUrl} fw={600} size="sm">
                    {selectedUrl.mapped_url_id}
                  </Text>
                  <Text c="dimmed" size="xs" truncate>
                    {selectedUrl.original_url}
                  </Text>
                </>
              ) : (
                <Input.Placeholder>Select a link</Input.Placeholder>
              )}
            </InputBase>
          </Combobox.Target>

          <Combobox.Dropdown>
            <Combobox.Options>
              {urls.map((url) => (
                <Combobox.Option value={String(url.id)} key={url.id} active={url.id === selectedUrlId}>
                  <Text className={classes.shortUrl} fw={600} size="sm">
                    {url.mapped_url_id}
                  </Text>
                  <Text c="dimmed" size="xs" truncate>
                    {url.original_url}
                  </Text>
                </Combobox.Option>
              ))}
            </Combobox.Options>
          </Combobox.Dropdown>
        </Combobox>
      </Box>
    </Card>
  );
}
